class Solution {
    public int mySqrt(int x) {
        if (x < 2) return x;

        long left = 1, right = x;
        long answer = 1;
        while (left <= right) {
            long mid = left + (right - left) / 2;
            if (mid * mid <= x) {
                answer = mid;
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }
        return (int) answer;
    }
}

class Solution {
    public boolean isPerfectSquare(int num) {
        long i = 1;
        while (i * i < num) i++;
        return i * i == num;
    }
}

class Solution {
    public boolean isPerfectSquare(int num) {
        long left = 1, right = num;
        while (left <= right) {
            long mid = left + (right - left) / 2;
            long square = mid * mid;
            if (square == num) return true;
            else if (square < num) left = mid + 1;
            else right = mid - 1;
        }
        return false;
    }
}

