class Solution extends VersionControl {
    public int firstBadVersion(int n) {
        int left = 1, right = n;
        while (left < right) {
            int mid = left + (right - left) / 2;
            if (isBadVersion(mid)) {
                right = mid; // mid might BE the first bad version -- keep it in range
            } else {
                left = mid + 1;
            }
        }
        return left;
    }
}

